/* ═══════════════════════════════════════════════════════════
   CHATBOT DEVIS — Composant réutilisable
   Simulé en front — prêt pour connexion webhook n8n
   ═══════════════════════════════════════════════════════════ */

/* URL webhook n8n — À REMPLACER par votre URL de production */
const N8N_WEBHOOK_URL = "https://votre-instance-n8n.com/webhook/devis-chatbot";

/* Grille tarifaire simulée (à ajuster selon vos vrais prix) */
const PRIX = {
  serigraphie: { base: 4.5, setup: 35 },
  broderie: { base: 6, setup: 25 },
  dtf: { base: 5.5, setup: 15 },
};

/* Logique de réponse simulée du bot */
function getBotResponse(messages, userMsg, collectedData) {
  const msg = userMsg.toLowerCase();
  const data = { ...collectedData };
  let response = "";
  let nextStep = data.step || "welcome";

  if (nextStep === "welcome") {
    nextStep = "produit";
    return {
      response: "Bonjour ! Je suis l'assistant PRINT.BZH. Je vais vous aider à chiffrer votre projet en quelques questions.\n\nQuel type de textile souhaitez-vous personnaliser ? (ex: t-shirts, sweats, casquettes, tote bags...)",
      data: { ...data, step: nextStep },
    };
  }

  if (nextStep === "produit") {
    data.produit = userMsg;
    nextStep = "quantite";
    response = `Parfait, ${userMsg} ! En quelle quantité ? (même approximative, ça nous aide à estimer)`;
  } else if (nextStep === "quantite") {
    const qty = parseInt(msg.replace(/\D/g, ""));
    data.quantite = qty || userMsg;
    nextStep = "technique";
    response = `Très bien, ${data.quantite} pièces. Quelle technique de marquage vous intéresse ?\n\n• Sérigraphie — idéale pour les grandes séries\n• Broderie — rendu haut de gamme\n• DTF — parfait pour les visuels complexes ou petites séries`;
  } else if (nextStep === "technique") {
    if (msg.includes("serigra") || msg.includes("sérigra")) {
      data.technique = "serigraphie";
    } else if (msg.includes("broder") || msg.includes("broderi")) {
      data.technique = "broderie";
    } else {
      data.technique = "dtf";
    }
    nextStep = "couleurs";
    response = "Combien de couleurs comporte votre visuel ? (1, 2, 3+)";
  } else if (nextStep === "couleurs") {
    data.couleurs = userMsg;
    nextStep = "details";
    response = "Vous avez déjà un visuel prêt ou vous avez besoin d'aide pour la création graphique ?";
  } else if (nextStep === "details") {
    data.details = userMsg;
    nextStep = "nom";
    response = "Super ! Pour vous envoyer le devis, j'ai besoin de quelques infos.\n\nQuel est votre nom ou le nom de votre entreprise ?";
  } else if (nextStep === "nom") {
    data.nom = userMsg;
    nextStep = "email";
    response = `Merci ${userMsg} ! Votre adresse email ?`;
  } else if (nextStep === "email") {
    data.email = userMsg;
    nextStep = "telephone";
    response = "Et un numéro de téléphone ? (optionnel, tapez 'non' pour passer)";
  } else if (nextStep === "telephone") {
    data.telephone = msg === "non" ? "" : userMsg;
    nextStep = "estimation";

    /* Calcul estimation */
    const qty = typeof data.quantite === "number" ? data.quantite : parseInt(String(data.quantite).replace(/\D/g, "")) || 50;
    const tech = data.technique || "dtf";
    const prix = PRIX[tech] || PRIX.dtf;
    const unitaire = prix.base + (qty < 50 ? 2 : qty < 100 ? 1 : 0);
    const total = (unitaire * qty + prix.setup).toFixed(2);

    response = `Merci pour toutes ces infos ! Voici une estimation indicative :\n\n📦 ${data.produit} × ${qty}\n🎨 ${tech.charAt(0).toUpperCase() + tech.slice(1)}\n💰 ~${unitaire.toFixed(2)}€/pièce HT\n📊 Total estimé : ~${total}€ HT\n\nCe tarif est indicatif. Un devis détaillé vous sera envoyé par email sous 24h. Notre équipe vous recontactera pour affiner selon votre visuel.\n\nMerci pour votre confiance ! 🙌`;

    /* Ici on déclencherait le webhook n8n */
    try {
      fetch(N8N_WEBHOOK_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...data,
          estimation_unitaire: unitaire,
          estimation_total: total,
          timestamp: new Date().toISOString(),
        }),
      }).catch(() => {});
    } catch (e) {}
  } else {
    response = "Merci, votre demande a bien été enregistrée ! Nous revenons vers vous très vite. 😊";
  }

  return { response, data: { ...data, step: nextStep } };
}

function ChatBot({ variant = "embedded" }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [collectedData, setCollectedData] = useState({ step: "welcome" });
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  const isEmbedded = variant === "embedded";

  /* Message de bienvenue */
  useEffect(() => {
    const timer = setTimeout(() => {
      const { response, data } = getBotResponse([], "", { step: "welcome" });
      setMessages([{ role: "bot", text: response }]);
      setCollectedData(data);
    }, 600);
    return () => clearTimeout(timer);
  }, []);

  /* Auto scroll */
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  const handleSend = () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input.trim();
    setInput("");
    setMessages((prev) => [...prev, { role: "user", text: userMsg }]);
    setIsTyping(true);

    setTimeout(() => {
      const { response, data } = getBotResponse(messages, userMsg, collectedData);
      setCollectedData(data);
      setMessages((prev) => [...prev, { role: "bot", text: response }]);
      setIsTyping(false);
    }, 800 + Math.random() * 800);
  };

  const containerStyle = isEmbedded
    ? {
        background: "rgba(10,10,10,0.25)",
        borderRadius: "8px",
        border: "1px solid rgba(245,237,224,0.1)",
        height: "560px",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
      }
    : {
        background: "#0A0A0A",
        borderRadius: "12px",
        border: "1px solid rgba(245,237,224,0.1)",
        height: "520px",
        width: "380px",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        boxShadow: "0 24px 80px rgba(0,0,0,0.4)",
      };

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div
        style={{
          padding: "16px 20px",
          borderBottom: "1px solid rgba(245,237,224,0.08)",
          display: "flex",
          alignItems: "center",
          gap: "12px",
          flexShrink: 0,
        }}
      >
        <div
          style={{
            width: "36px",
            height: "36px",
            borderRadius: "50%",
            background: "var(--orange)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            flexShrink: 0,
          }}
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="var(--light)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z" />
          </svg>
        </div>
        <div>
          <div style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.95rem", color: "var(--light)" }}>
            Assistant devis
          </div>
          <div style={{ fontFamily: "var(--font-body)", fontSize: "0.7rem", color: "rgba(245,237,224,0.5)", display: "flex", alignItems: "center", gap: "6px" }}>
            <div style={{ width: "6px", height: "6px", borderRadius: "50%", background: "#4ade80" }} />
            En ligne
          </div>
        </div>
      </div>

      {/* Messages */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          padding: "20px",
          display: "flex",
          flexDirection: "column",
          gap: "16px",
        }}
      >
        {messages.map((msg, i) => (
          <div
            key={i}
            style={{
              display: "flex",
              justifyContent: msg.role === "user" ? "flex-end" : "flex-start",
              animation: "revealUp 0.4s ease-out both",
            }}
          >
            <div
              style={{
                maxWidth: "85%",
                padding: "12px 16px",
                borderRadius: msg.role === "user" ? "16px 16px 4px 16px" : "16px 16px 16px 4px",
                background: msg.role === "user" ? "var(--orange)" : "rgba(245,237,224,0.08)",
                color: msg.role === "user" ? "var(--light)" : "var(--light)",
                fontFamily: "var(--font-body)",
                fontSize: "0.88rem",
                fontWeight: 400,
                lineHeight: 1.6,
                whiteSpace: "pre-line",
              }}
            >
              {msg.text}
            </div>
          </div>
        ))}

        {/* Typing indicator */}
        {isTyping && (
          <div style={{ display: "flex", justifyContent: "flex-start" }}>
            <div
              style={{
                padding: "12px 20px",
                borderRadius: "16px 16px 16px 4px",
                background: "rgba(245,237,224,0.08)",
                display: "flex",
                gap: "4px",
                alignItems: "center",
              }}
            >
              {[0, 1, 2].map((d) => (
                <div
                  key={d}
                  style={{
                    width: "6px",
                    height: "6px",
                    borderRadius: "50%",
                    background: "rgba(245,237,224,0.4)",
                    animation: `scrollPulse 1.2s ease-in-out ${d * 0.2}s infinite`,
                  }}
                />
              ))}
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div
        style={{
          padding: "16px 20px",
          borderTop: "1px solid rgba(245,237,224,0.08)",
          display: "flex",
          gap: "10px",
          flexShrink: 0,
        }}
      >
        <input
          type="text"
          placeholder="Tapez votre message..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
          style={{
            flex: 1,
            padding: "12px 16px",
            background: "rgba(245,237,224,0.06)",
            border: "1px solid rgba(245,237,224,0.12)",
            borderRadius: "24px",
            color: "var(--light)",
            fontFamily: "var(--font-body)",
            fontSize: "0.88rem",
            outline: "none",
          }}
        />
        <button
          onClick={handleSend}
          disabled={isTyping || !input.trim()}
          style={{
            width: "42px",
            height: "42px",
            borderRadius: "50%",
            background: input.trim() && !isTyping ? "var(--orange)" : "rgba(245,237,224,0.08)",
            border: "none",
            cursor: input.trim() && !isTyping ? "pointer" : "default",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            transition: "all 0.3s ease",
            flexShrink: 0,
          }}
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={input.trim() && !isTyping ? "var(--light)" : "rgba(245,237,224,0.3)"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="22" y1="2" x2="11" y2="13" />
            <polygon points="22 2 15 22 11 13 2 9 22 2" />
          </svg>
        </button>
      </div>
    </div>
  );
}

